{"file_path":"/home/user/projects/wf_agents/internal/config/merge.go","old_string":"func mergeIdleRules(base, override []IdleRule) []IdleRule {
	index := make(map[string]int)
	result := make([]IdleRule, 0, len(base)+len(override))

	for _, r := range base {
		index[r.Match] = len(result)
		result = append(result, r)
	}

	for _, r := range override {
		if idx, exists := index[r.Match]; exists {
			result[idx] = r // replace
		} else {
			index[r.Match] = len(result)
			result = append(result, r)
		}
